import{_ as o,o as a,c as r,a0 as t}from"./chunks/framework.jwovEGr5.js";const n="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",y=JSON.parse('{"title":"Edit Your Profile & Password","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/your-profile.md","filePath":"getting-started/your-profile.md"}'),s={name:"getting-started/your-profile.md"};function i(l,e,d,u,p,h){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="edit-your-profile-password" tabindex="-1">Edit Your Profile &amp; Password <a class="header-anchor" href="#edit-your-profile-password" aria-label="Permalink to &quot;Edit Your Profile &amp; Password&quot;">​</a></h1><p>Your profile is where you update your own display name, email, and password. Every logged‑in user has one, whatever their role.</p><h2 id="opening-your-profile" tabindex="-1">Opening your profile <a class="header-anchor" href="#opening-your-profile" aria-label="Permalink to &quot;Opening your profile&quot;">​</a></h2><p><img src="'+n+'" alt="Profile page"></p><p>Select your <strong>name</strong> in the top‑right corner of the app to open your profile page.</p><h2 id="updating-your-display-name-and-email" tabindex="-1">Updating your display name and email <a class="header-anchor" href="#updating-your-display-name-and-email" aria-label="Permalink to &quot;Updating your display name and email&quot;">​</a></h2><ol><li>On the profile page, edit your <strong>display name</strong> and/or <strong>email</strong>.</li><li>Save your changes.</li></ol><p>Your display name is how you appear to others in the app (for example, next to actions you take). Your email may be used for account‑related messages.</p><h2 id="changing-your-password" tabindex="-1">Changing your password <a class="header-anchor" href="#changing-your-password" aria-label="Permalink to &quot;Changing your password&quot;">​</a></h2><ol><li>On the profile page, find the <strong>password</strong> section.</li><li>Enter your new password (you may be asked for your current one).</li><li>Save.</li></ol><p>Use a password you don&#39;t reuse elsewhere. If you were given a temporary password when your account was created, this is where you replace it with your own.</p><h2 id="if-you-were-forced-to-change-your-password" tabindex="-1">If you were forced to change your password <a class="header-anchor" href="#if-you-were-forced-to-change-your-password" aria-label="Permalink to &quot;If you were forced to change your password&quot;">​</a></h2><p>Sometimes an admin creates your account with a temporary password and requires you to set your own the first time you log in. If so, you&#39;ll be sent to the password step automatically — just choose a new password and save.</p><h2 id="what-you-can-t-change-here" tabindex="-1">What you can&#39;t change here <a class="header-anchor" href="#what-you-can-t-change-here" aria-label="Permalink to &quot;What you can&#39;t change here&quot;">​</a></h2><ul><li><strong>Your role</strong> — roles are set by admins, not on your own profile. See <a href="./../roles/overview.html">Roles Explained</a>.</li><li><strong>Which kingdom or alliance you belong to</strong> — that&#39;s also managed by admins.</li></ul><p>If any of those need to change, contact your Alliance Leader, King, or Supreme Admin.</p><h2 id="forgot-your-current-password" tabindex="-1">Forgot your current password? <a class="header-anchor" href="#forgot-your-current-password" aria-label="Permalink to &quot;Forgot your current password?&quot;">​</a></h2><p>If you can&#39;t sign in at all, use <a href="./forgot-password.html">Reset a Forgotten Password</a> instead — the profile page requires you to already be logged in.</p>',18)])])}const c=o(s,[["render",i]]);export{y as __pageData,c as default};
